-- Table: ##votreschema.votretable##

-- DROP TABLE IF EXISTS ##votreschema.votretable##;

CREATE TABLE IF NOT EXISTS ##votreschema.votretable##
(
    id_socle_txt SERIAL NOT NULL,
    id character varying(7),
    nature character varying(255),
    famille character varying(50),
    calque character varying(9),
    calque_alt character varying(9),
    calque_mat character varying(9),
    pcrs character varying(50),
    placement character varying(15),
    charte character varying(50),
    commentaires character varying(254),
    sig character varying(25),
    type_cao character varying(20),
    attribut_altitude character varying(50),
    attribut_matricule character varying(50),
    "CategorieThematiquePCRSType" character varying(2),
    "NatureReseauPCRSType" character varying(10),
    "NatureAffleurantPCRSType" character varying(2),
    "CategorieMurPCRSType" character varying(2),
    "SectionPilierPCRSType" character varying(2),
    date_modif date,
    date_crea date,
    id_nature character varying(255),
    CONSTRAINT id_socle_txt_pkey PRIMARY KEY (id_socle_txt)
        USING INDEX TABLESPACE ##votretablespace##
)

COMMENT ON TABLE ##votreschema.votretable##
    IS 'Table textuelle des objets présents dans le Standard topographique régional régional et les objets relatifs aux besoins de Standard topographique régional';

COMMENT ON COLUMN ##votreschema.votretable##.id_socle_txt
    IS 'Identifiant unique';

COMMENT ON COLUMN ##votreschema.votretable##.id
    IS 'id unique des objets topographiques';

COMMENT ON COLUMN ##votreschema.votretable##.nature
    IS 'désignation ou description correspondant à l''objet';

COMMENT ON COLUMN ##votreschema.votretable##.famille
    IS 'famille de classification technique de l''objet';

COMMENT ON COLUMN ##votreschema.votretable##.calque
    IS 'calque de classement de l''objet dans le dessin CAO';

COMMENT ON COLUMN ##votreschema.votretable##.calque_alt
    IS 'calque de classement des points topo dans le dessin CAO';

COMMENT ON COLUMN ##votreschema.votretable##.calque_mat
    IS 'calque de classement de points topo dans le dessin CAO';

COMMENT ON COLUMN ##votreschema.votretable##.pcrs
    IS 'nom de la classe d''objets au PCRS';

COMMENT ON COLUMN ##votreschema.votretable##.placement
    IS 'emplacement de l''objet: Sous-sol/Surface/Information';

COMMENT ON COLUMN ##votreschema.votretable##.charte
    IS 'appartenance de l''objet, Standard topographique régional ou Standard topographique régional';

COMMENT ON COLUMN ##votreschema.votretable##.commentaires
    IS 'commentaires et informations à renseigner';

COMMENT ON COLUMN ##votreschema.votretable##.date_modif
    IS 'date de modification de l''objet';

COMMENT ON COLUMN ##votreschema.votretable##.date_crea
    IS 'date de création de l''objet';

COMMENT ON COLUMN ##votreschema.votretable##.id_nature
    IS 'Concaténation de l''id et de la nature de l''objet';

